INSERT INTO `Page` (`id`, `title`, `slug`, `content`, `published`, `createdAt`, `updatedAt`, `metaDescription`, `metaTitle`) VALUES
(1, 'Tentang Lanyard Jakarta', 'tentang', '<h2>Profil Lanyard Jakarta</h2>\n        <p>Lanyard Jakarta adalah produsen spesialis cetak tali gantungan ID card / lanyard premium custom terpercaya di Indonesia. Kami berdedikasi untuk memberikan hasil cetak kualitas terbaik bagi kebutuhan branding perusahaan, instansi pemerintahan, kepanitiaan event, organisasi, maupun penggunaan personal.</p>\n        \n        <h2>Mengapa Memilih Kami?</h2>\n        <p>Kami memahami bahwa tali gantungan ID card bukan sekadar alat bantu membawa kartu identitas, melainkan media representasi brand Anda. Oleh karena itu, kami memberikan beberapa keunggulan utama:</p>\n        <ul>\n          <li><strong>Bahan Tissue Premium:</strong> Kami menggunakan bahan kain lanyard berstruktur lembut (tipe tissue polyester) yang sangat nyaman di kulit leher, tidak menyebabkan gatal, serta tebal dan tahan lama.</li>\n          <li><strong>Cetak Sublimasi Full Color:</strong> Menggunakan printer khusus sublimasi modern beresolusi tinggi dengan tinta impor premium, menghasilkan degradasi warna yang halus, detail yang tajam, dan tidak luntur meski dicuci berkali-kali.</li>\n          <li><strong>Aksesoris Berkualitas Tinggi:</strong> Pilihan kait besi stainless steel tebal anti karat, stopper plastik pengunci kuat (mutu ekspor), serta card holder tebal berkualitas tinggi.</li>\n          <li><strong>Pengerjaan Kilat & Tepat Waktu:</strong> Didukung oleh kapasitas produksi harian yang besar dan tim profesional, kami memastikan pesanan Anda selesai tepat sesuai jadwal kesepakatan.</li>\n        </ul>\n        \n        <blockquote>\n          \"Komitmen kami adalah menyajikan produk berkualitas tinggi dengan pelayanan prima untuk mendukung kesuksesan promosi dan branding instansi Anda.\"\n        </blockquote>\n        \n        <h2>Visi & Misi Kami</h2>\n        <p>Menjadi mitra tepercaya nomor satu di Indonesia dalam penyediaan media promosi dan perlengkapan identitas corporate, dengan mengutamakan kepuasan pelanggan, kualitas produk, dan ketepatan waktu pengiriman.</p>', 1, '2026-06-23 11:20:13.000', '2026-06-23 11:20:13.000', 'Temukan profil lengkap Lanyard Jakarta, penyedia layanan cetak tali gantungan lanyard custom kualitas premium terpercaya dengan teknologi cetak digital sublimasi terbaik.', 'Tentang Kami - Lanyard Jakarta Premium Custom'),
(2, 'Hubungi Kontak Kami', 'kontak', '<h2>Layanan Konsultasi & Pemesanan</h2>\n        <p>Tim layanan pelanggan Lanyard Jakarta siap membantu Anda merancang desain, memilih bahan, hingga proses kalkulasi harga terbaik untuk kebutuhan promosi corporate Anda.</p>\n        \n        <h2>Informasi Kontak Resmi</h2>\n        <p>Silakan hubungi kami melalui salah satu saluran komunikasi di bawah ini untuk respon cepat:</p>\n        <ul>\n          <li><strong>WhatsApp (Hotline):</strong> +62 822-1020-0700</li>\n          <li><strong>Email Resmi:</strong> info@primagraphia.co.id / info@lanyardjakarta.co.id</li>\n          <li><strong>Jam Operasional:</strong> Senin - Sabtu, Pukul 09.00 - 21.00 WIB (Minggu & Hari Libur Nasional tutup)</li>\n        </ul>\n        \n        <h2>Kantor & Workshop Produksi</h2>\n        <p>Anda juga dapat mengunjungi store utama kami untuk melihat langsung sampel bahan tali dan portofolio cetak yang telah kami kerjakan sebelumnya:</p>\n        <p><strong>Alamat:</strong> Jl. Salemba Raya No. 34-36, Senen, Jakarta Pusat, DKI Jakarta 10430</p>\n        \n        <h2>Kirim Pesan Instan</h2>\n        <p>Jika Anda memiliki pertanyaan spesifik mengenai penawaran harga formal (Quotation), pembuatan desain mockup gratis, atau sampel fisik, jangan ragu untuk menghubungi layanan WhatsApp customer service kami. Kami akan merespons pertanyaan Anda sesegera mungkin selama jam kerja operasional.</p>', 1, '2026-06-23 11:20:13.000', '2026-06-23 11:20:13.000', 'Hubungi tim customer service Lanyard Jakarta untuk pemesanan tali lanyard custom premium, negosiasi harga kuantitas besar, atau informasi detail lainnya.', 'Hubungi Kami - Layanan Pelanggan Lanyard Jakarta'),
(3, 'Kebijakan Privasi', 'kebijakan', '<h2>Perlindungan Data & Desain Pelanggan</h2>\n        <p>Di Lanyard Jakarta, kami sangat menjunjung tinggi kerahasiaan informasi personal dan hak atas kekayaan intelektual (desain) dari setiap pelanggan kami. Kebijakan privasi ini menjelaskan bagaimana kami mengelola, menggunakan, dan melindungi data Anda.</p>\n        \n        <h2>1. Kerahasiaan Hak Cipta Desain</h2>\n        <p>Setiap file desain, aset logo instansi, gambar mockup, dan instruksi penataan merek yang Anda kirimkan kepada kami sepenuhnya merupakan hak milik eksklusif Anda. Kami berkomitmen untuk:</p>\n        <ul>\n          <li>Tidak menyalahgunakan desain atau logo Anda untuk kepentingan komersial pihak ketiga tanpa persetujuan tertulis.</li>\n          <li>Menyimpan file master desain Anda dalam server yang aman untuk memudahkan proses produksi ulang (repeat order) di kemudian hari.</li>\n        </ul>\n        \n        <h2>2. Data Transaksi Pemesanan</h2>\n        <p>Data pribadi yang dikumpulkan selama pengajuan kalkulator harga atau pemesanan (termasuk nama, email, nomor telepon, alamat pengiriman, dan riwayat transaksi) hanya digunakan untuk keperluan pemrosesan pesanan, pengiriman barang, komunikasi status produksi, serta layanan purna jual.</p>\n        \n        <h2>3. Keamanan Informasi</h2>\n        <p>Kami menerapkan langkah-langkah keamanan fisik, teknis, dan administratif untuk melindungi data pribadi Anda dari akses yang tidak sah, perubahan ilegal, penyalahgunaan, atau kebocoran informasi.</p>\n        \n        <h2>4. Perubahan Kebijakan</h2>\n        <p>Kami dapat memperbarui kebijakan privasi ini sewaktu-waktu seiring dengan perubahan teknologi dan regulasi pemerintah. Pelanggan disarankan untuk memeriksa halaman ini secara berkala.</p>', 1, '2026-06-23 11:20:13.000', '2026-06-23 11:20:13.000', 'Kebijakan privasi pelanggan Lanyard Jakarta mengenai hak cipta desain lanyard custom, keamanan data transaksi pemesanan, dan kerahasiaan informasi personal.', 'Kebijakan Privasi Pelanggan - Lanyard Jakarta'),
(4, 'Syarat & Ketentuan', 'syarat-ketentuan', '<h2>Aturan Main Pemesanan Lanyard Custom</h2>\n        <p>Terima kasih telah mempercayakan pengerjaan tali lanyard corporate Anda kepada Lanyard Jakarta. Harap membaca Syarat & Ketentuan di bawah ini sebelum menyetujui pemesanan barang:</p>\n        \n        <h2>1. Jumlah Minimum Pemesanan (MOQ)</h2>\n        <p>Kami melayani pemesanan tali lanyard custom dengan ketentuan minimum order yang fleksibel. Jumlah harga satuan yang tertera pada sistem kalkulator akan secara otomatis menyesuaikan dengan volume pesanan Anda (makin banyak kuantitas, harga per pcs akan semakin murah).</p>\n        \n        <h2>2. Persetujuan Mockup Desain (Approval)</h2>\n        <ul>\n          <li>Proses cetak baru akan dimulai setelah pelanggan menyetujui mockup desain visual (layout gambar) yang dikirimkan oleh tim desainer kami via WhatsApp atau email.</li>\n          <li>Kami tidak bertanggung jawab atas kesalahan ejaan kata, penulisan nama, tata letak logo, atau spesifikasi aksesoris setelah pelanggan memberikan konfirmasi persetujuan cetak (mockup approved).</li>\n        </ul>\n        \n        <h2>3. Sistem Pembayaran</h2>\n        <ul>\n          <li>Pemesanan wajib disertai dengan pembayaran Down Payment (DP) minimal sebesar 50% dari total nilai tagihan invoice sebagai tanda jadi produksi.</li>\n          <li>Sisa pelunasan (50%) wajib dibayarkan secara penuh setelah barang dinyatakan selesai diproduksi dan siap dikirim ke alamat tujuan.</li>\n        </ul>\n        \n        <h2>4. Pengiriman & Garansi Kualitas</h2>\n        <p>Kami mengirimkan pesanan menggunakan ekspedisi terpercaya (JNE, J&T, Sicepat, Lalamove, GoSend, dsb.). Segala kerusakan atau cacat produksi akibat kelalaian tim kami wajib dilaporkan maksimal 3 hari sejak barang diterima untuk mendapatkan fasilitas klaim penggantian atau perbaikan gratis.</p>', 1, '2026-06-23 11:20:13.000', '2026-06-23 11:20:13.000', 'Pahami syarat dan ketentuan pemesanan cetak tali lanyard custom, kebijakan persetujuan mockup desain, syarat pembayaran, dan jaminan garansi retur.', 'Syarat & Ketentuan Pemesanan - Lanyard Jakarta'),
(5, 'Promo & Penawaran Terbaru', 'promo', '<h2>Dapatkan Penawaran Eksklusif Lanyard Jakarta</h2>\n        <p>Kami selalu menghadirkan berbagai program promo menarik khusus untuk membantu menghemat pengeluaran anggaran promosi dan operasional corporate Anda. Berikut adalah beberapa promo aktif saat ini:</p>\n        \n        <h2>1. Gratis Layanan Jasa Desain Mockup</h2>\n        <p>Kesulitan membuat desain layout lanyard? Jangan khawatir! Kirimkan file logo resmi beserta preferensi warna instansi Anda, dan tim desainer profesional kami akan membuatkan mockup desain layout visual lanyard secara <strong>GRATIS tanpa dipungut biaya sepeser pun</strong> (Maksimal 3x revisi).</p>\n        \n        <h2>2. Diskon Volume Pemesanan Skala Besar</h2>\n        <p>Dapatkan harga khusus super hemat untuk pemesanan cetak tali lanyard dalam volume besar (lebih dari 500 pcs). Silakan berkonsultasi langsung dengan admin customer service kami untuk mendapatkan harga penawaran resmi (Quotation proposal) dengan potongan diskon yang melimpah.</p>\n        \n        <h2>3. Paket Bundling Lanyard & Holder Premium</h2>\n        <p>Nikmati harga paket hemat terjangkau untuk setiap pemesanan tali lanyard sublimasi full color yang langsung sepaket dengan casing / wadah pelindung ID Card (Card Holder) kualitas premium tebal. Pilihan casing karet, akrilik transparan, hingga wadah kulit sintetis elegan.</p>\n        \n        <blockquote>\n          *Syarat dan ketentuan berlaku. Promo dapat berubah sewaktu-waktu tanpa pemberitahuan sebelumnya. Hubungi WhatsApp Customer Service kami untuk klaim promo Anda hari ini!\n        </blockquote>', 1, '2026-06-23 11:20:13.000', '2026-06-23 11:20:13.000', 'Cek promo dan penawaran eksklusif cetak tali lanyard gantungan ID card custom dari Lanyard Jakarta. Nikmati gratis jasa desain dan diskon kuantitas besar.', 'Promo Cetak Lanyard Custom Murah - Lanyard Jakarta');

